import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AdminDashboard = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [uploadLoading, setUploadLoading] = useState(false);
  const [dragActive, setDragActive] = useState(false);
  const [imageInputType, setImageInputType] = useState('url'); // 'url' or 'file'
  const [formData, setFormData] = useState({
    name: '',
    price: '',
    description: '',
    image: '',
    category: 'herbs',
    inStock: true
  });

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      setLoading(true);
      const response = await axios.get('/api/products');
      setProducts(response.data.products);
      setError('');
    } catch (err) {
      setError('Failed to fetch products');
      console.error('Error fetching products:', err);
    } finally {
      setLoading(false);
    }
  };

  const onChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === 'checkbox' ? checked : value
    });
  };

  // Drag and drop handlers
  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleImageUpload(e.dataTransfer.files[0]);
    }
  };

  const handleImageUpload = async (file) => {
    if (!file) return;

    // Check file type
    if (!file.type.match('image.*')) {
      setError('Please select an image file');
      return;
    }

    // Check file size (5MB limit)
    if (file.size > 5 * 1024 * 1024) {
      setError('Image size should be less than 5MB');
      return;
    }

    setUploadLoading(true);
    setError('');

    const formData = new FormData();
    formData.append('image', file);

    try {
      const token = localStorage.getItem('token');
      const response = await axios.post('/api/products/upload', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
          'Authorization': `Bearer ${token}`
        }
      });

      setFormData({
        ...formData,
        image: response.data.imageUrl
      });
    } catch (err) {
      setError('Failed to upload image');
      console.error('Image upload error:', err);
    } finally {
      setUploadLoading(false);
    }
  };

  const handleFileSelect = (e) => {
    const file = e.target.files[0];
    if (file) {
      handleImageUpload(file);
    }
  };

  const onSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const token = localStorage.getItem('token');
      const config = {
        headers: { Authorization: `Bearer ${token}` }
      };

      if (editingProduct) {
        await axios.put(`/api/products/${editingProduct._id}`, formData, config);
      } else {
        await axios.post('/api/products', formData, config);
      }

      await fetchProducts();
      resetForm();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save product');
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (product) => {
    setEditingProduct(product);
    setFormData({
      name: product.name,
      price: product.price,
      description: product.description,
      image: product.image,
      category: product.category,
      inStock: product.inStock
    });
    setShowAddForm(true);
  };

  const handleDelete = async (productId) => {
    if (!window.confirm('Are you sure you want to delete this product?')) {
      return;
    }

    try {
      const token = localStorage.getItem('token');
      const config = {
        headers: { Authorization: `Bearer ${token}` }
      };

      await axios.delete(`/api/products/${productId}`, config);
      await fetchProducts();
    } catch (err) {
      setError('Failed to delete product');
      console.error('Error deleting product:', err);
    }
  };

  const resetForm = () => {
    setFormData({
      name: '',
      price: '',
      description: '',
      image: '',
      category: 'herbs',
      inStock: true
    });
    setEditingProduct(null);
    setShowAddForm(false);
  };

  const categories = ['herbs', 'teas', 'oils', 'supplements', 'other'];

  return (
    <div className="container">
      <div className="admin-header">
        <h1>Admin Dashboard</h1>
        <button 
          className="btn btn-primary" 
          onClick={() => setShowAddForm(!showAddForm)}
        >
          {showAddForm ? 'Cancel' : 'Add New Product'}
        </button>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      {showAddForm && (
        <div className="card mb-20">
          <div className="card-header">
            <h2>{editingProduct ? 'Edit Product' : 'Add New Product'}</h2>
          </div>
          <div className="card-body">
            <form onSubmit={onSubmit}>
              <div className="form-grid">
                <div className="form-group">
                  <label htmlFor="name">Product Name</label>
                  <input
                    type="text"
                    id="name"
                    name="name"
                    value={formData.name}
                    onChange={onChange}
                    className="form-control"
                    required
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="price">Price</label>
                  <input
                    type="number"
                    id="price"
                    name="price"
                    value={formData.price}
                    onChange={onChange}
                    className="form-control"
                    step="0.01"
                    min="0"
                    required
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="category">Category</label>
                  <select
                    id="category"
                    name="category"
                    value={formData.category}
                    onChange={onChange}
                    className="form-control"
                  >
                    {categories.map(cat => (
                      <option key={cat} value={cat}>
                        {cat.charAt(0).toUpperCase() + cat.slice(1)}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="form-group full-width">
                  <label>Product Image</label>

                  {/* Image Input Type Selector */}
                  <div className="image-input-type-selector mb-3">
                    <button
                      type="button"
                      className={`btn ${imageInputType === 'file' ? 'btn-primary' : 'btn-secondary'}`}
                      onClick={() => setImageInputType('file')}
                    >
                      Upload Image
                    </button>
                    <button
                      type="button"
                      className={`btn ${imageInputType === 'url' ? 'btn-primary' : 'btn-secondary'}`}
                      onClick={() => setImageInputType('url')}
                    >
                      Image URL
                    </button>
                  </div>

                  {/* File Upload Section */}
                  {imageInputType === 'file' && (
                    <div className="image-upload-section">
                      <div
                        className={`drag-drop-area ${dragActive ? 'drag-active' : ''} ${uploadLoading ? 'uploading' : ''}`}
                        onDragEnter={handleDrag}
                        onDragLeave={handleDrag}
                        onDragOver={handleDrag}
                        onDrop={handleDrop}
                      >
                        <input
                          type="file"
                          id="image-file"
                          accept="image/*"
                          onChange={handleFileSelect}
                          className="hidden"
                        />
                        {uploadLoading ? (
                          <div className="upload-loading">
                            <p>Uploading image...</p>
                          </div>
                        ) : (
                          <div className="upload-prompt">
                            <p>Drag & drop an image here or click to select</p>
                            <button
                              type="button"
                              className="btn btn-secondary"
                              onClick={() => document.getElementById('image-file').click()}
                            >
                              Choose File
                            </button>
                          </div>
                        )}
                      </div>

                      {/* Image Preview */}
                      {formData.image && (
                        <div className="image-preview">
                          <img 
                            src={formData.image.startsWith('http') ? formData.image : `http://localhost:5000${formData.image}`}
                            alt="Product preview"
                            className="preview-image"
                          />
                          <button
                            type="button"
                            className="btn btn-danger btn-sm remove-image"
                            onClick={() => setFormData({...formData, image: ''})}
                          >
                            Remove
                          </button>
                        </div>
                      )}
                    </div>
                  )}

                  {/* URL Input Section */}
                  {imageInputType === 'url' && (
                    <div className="image-url-section">
                      <input
                        type="text"
                        id="image"
                        name="image"
                        value={formData.image}
                        onChange={onChange}
                        className="form-control"
                        placeholder="https://example.com/image.jpg"
                      />

                      {/* Image Preview for URL */}
                      {formData.image && (
                        <div className="image-preview">
                          <img 
                            src={formData.image}
                            alt="Product preview"
                            className="preview-image"
                            onError={(e) => {
                              e.target.src = 'https://via.placeholder.com/300x300?text=Invalid+Image';
                            }}
                          />
                          <button
                            type="button"
                            className="btn btn-danger btn-sm remove-image"
                            onClick={() => setFormData({...formData, image: ''})}
                          >
                            Remove
                          </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>

                <div className="form-group full-width">
                  <label htmlFor="description">Description</label>
                  <textarea
                    id="description"
                    name="description"
                    value={formData.description}
                    onChange={onChange}
                    className="form-control"
                    rows="4"
                    required
                  />
                </div>

                <div className="form-group">
                  <label className="checkbox-label">
                    <input
                      type="checkbox"
                      name="inStock"
                      checked={formData.inStock}
                      onChange={onChange}
                    />
                    In Stock
                  </label>
                </div>
              </div>

              <div className="form-actions">
                <button 
                  type="submit" 
                  className="btn btn-primary"
                  disabled={loading}
                >
                  {loading ? 'Saving...' : (editingProduct ? 'Update Product' : 'Add Product')}
                </button>
                <button 
                  type="button" 
                  className="btn btn-secondary"
                  onClick={resetForm}
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="card">
        <div className="card-header">
          <h2>Products ({products.length})</h2>
        </div>
        <div className="card-body">
          {loading ? (
            <div className="loading">Loading products...</div>
          ) : products.length === 0 ? (
            <div className="text-center">
              <h3>No products found</h3>
              <p>Add your first product to get started</p>
            </div>
          ) : (
            <div className="admin-products-table">
              <table>
                <thead>
                  <tr>
                    <th>Image</th>
                    <th>Name</th>
                    <th>Price</th>
                    <th>Category</th>
                    <th>Stock</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {products.map(product => (
                    <tr key={product._id}>
                      <td>
                        <img 
                          src={product.image} 
                          alt={product.name}
                          className="admin-product-image"
                        />
                      </td>
                      <td>{product.name}</td>
                      <td>${product.price.toFixed(2)}</td>
                      <td>{product.category}</td>
                      <td>
                        <span className={`stock-badge ${product.inStock ? 'in-stock' : 'out-of-stock'}`}>
                          {product.inStock ? 'In Stock' : 'Out of Stock'}
                        </span>
                      </td>
                      <td>
                        <button 
                          className="btn btn-secondary btn-sm"
                          onClick={() => handleEdit(product)}
                        >
                          Edit
                        </button>
                        <button 
                          className="btn btn-danger btn-sm"
                          onClick={() => handleDelete(product._id)}
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
